//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = async function (e) {
    console.log("▷ sbm_save_submitdone ==================");
/*
<!-- 저장 TR -->         
<script language=JavaScript for=tr_save event=OnFail()>
    cfShowError(tr_save);
    cfDisableKeyData();
	cfDisableBtn([bSave]);	 
<script language=JavaScript for=tr_save event=OnSuccess()>
    cfAlertMsg(MSG_CM_INF_001);
    f_Header();
    f_Retrieve() ;
    cfDisableKeyData();
	cfDisableBtn([bSave]);	  
*/
    if( e.responseJSON.resultDataSet[0].Code != 0 ) {
        console.log("   --- tr_save - OnFail ");
        //cfShowError(tr_save);   // 공통에서 뿌림
        $c.gus.cfDisableKeyData();
	    //$c.gus.cfDisableBtnOnly([bnt_btSave]);
        $c.gus.cfDisableBtn( [$c.gus.getctrlBtn('bSave')] );
    }
    else {
        // console.log("   --- tr_save - OnSuccess ");
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        //f_Header();
        scwin.f_Retrieve() ;
        $c.gus.cfDisableKeyData();
	    //$c.gus.cfDisableBtnOnly([btn_btSave]);
        $c.gus.cfDisableBtn( [$c.gus.getctrlBtn('bSave')] );
    }
};


//-------------------------------------------------------------------------
// 닫기 버튼 클릭
//-------------------------------------------------------------------------
scwin.btn_close_onclick = function (e) {
    $c.win.closePopup(["N/A"]);
};
